// src/components/VendaForm.jsx
import React, { useState, useEffect } from 'react';
import { getProdutos, getClientes, realizarVenda, getVendasPorProduto } from '../services/api';

function VendaForm() {
    const [produtos, setProdutos] = useState([]);
    const [clientes, setClientes] = useState([]);
    const [venda, setVenda] = useState({ produtoId: '', clienteId: '', quantidade: '' });
    const [vendasRealizadas, setVendasRealizadas] = useState([]);
    const [produtoSelecionado, setProdutoSelecionado] = useState(null);

    useEffect(() => {
        carregarDados();
    }, []);

    const carregarDados = async () => {
        try {
            const [prodRes, clientRes] = await Promise.all([
                getProdutos(),
                getClientes()
            ]);
            setProdutos(prodRes.data);
            setClientes(clientRes.data);
        } catch (err) {
            console.error('Erro:', err);
        }
    };

    const handleVenda = async (e) => {
        e.preventDefault();
        try {
            const response = await realizarVenda(venda.produtoId, venda.clienteId, venda.quantidade);
            alert(response.data.mensagem);
            setVenda({ produtoId: '', clienteId: '', quantidade: '' });
            verVendasProduto(venda.produtoId);
        } catch (err) {
            alert(err.response?.data?.message || 'Erro na venda');
        }
    };

    const verVendasProduto = async (produtoId) => {
        try {
            const response = await getVendasPorProduto(produtoId);
            setVendasRealizadas(response.data);
            const produto = produtos.find(p => p.id === parseInt(produtoId));
            setProdutoSelecionado(produto);
        } catch (err) {
            console.error('Erro:', err);
        }
    };

    return (
        <div style={styles.container}>
            <h2>💰 Realizar Venda</h2>

            <form onSubmit={handleVenda} style={styles.form}>
                <select
                    value={venda.produtoId}
                    onChange={(e) => setVenda({ ...venda, produtoId: e.target.value })}
                    style={styles.select}
                    required
                >
                    <option value="">Selecione o Produto</option>
                    {produtos.map(p => (
                        <option key={p.id} value={p.id}>{p.nome} - R$ {p.preco} (Estoque: {p.quantidadeEstoque})</option>
                    ))}
                </select>

                <select
                    value={venda.clienteId}
                    onChange={(e) => setVenda({ ...venda, clienteId: e.target.value })}
                    style={styles.select}
                    required
                >
                    <option value="">Selecione o Cliente</option>
                    {clientes.map(c => (
                        <option key={c.id} value={c.id}>{c.nome}</option>
                    ))}
                </select>

                <input
                    type="number"
                    placeholder="Quantidade"
                    value={venda.quantidade}
                    onChange={(e) => setVenda({ ...venda, quantidade: e.target.value })}
                    style={styles.input}
                    required
                />

                <button type="submit" style={styles.button}>Realizar Venda</button>
            </form>

            {produtoSelecionado && (
                <div style={styles.vendasSection}>
                    <h3>Vendas do Produto: {produtoSelecionado.nome}</h3>
                    <table style={styles.table}>
                        <thead>
                            <tr><th>Cliente</th><th>Quantidade</th><th>Valor Total</th><th>Data</th></tr>
                        </thead>
                        <tbody>
                            {vendasRealizadas.map(v => (
                                <tr key={v.id}>
                                    <td>{v.cliente?.nome}</td>
                                    <td>{v.quantidade}</td>
                                    <td>R$ {v.valorTotal?.toFixed(2)}</td>
                                    <td>{new Date(v.dataVenda).toLocaleString()}</td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
            )}
        </div>
    );
}

const styles = {
    container: { padding: '2rem' },
    form: { marginBottom: '1rem', padding: '1rem', border: '1px solid #ddd', borderRadius: '4px', display: 'flex', gap: '0.5rem', flexWrap: 'wrap' },
    select: { padding: '0.5rem', borderRadius: '4px', border: '1px solid #ddd', flex: '1' },
    input: { padding: '0.5rem', borderRadius: '4px', border: '1px solid #ddd', flex: '1' },
    button: { padding: '0.5rem 1rem', backgroundColor: '#3498db', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' },
    vendasSection: { marginTop: '2rem' },
    table: { width: '100%', borderCollapse: 'collapse', marginTop: '1rem', border: '1px solid #ddd' }
};

export default VendaForm;
